SELECT AVG(avg_run_time) AS average_run_time
FROM job_status
WHERE tool_id = 1;

SELECT project_name 
FROM projects 
ORDER BY project_name ASC;

SELECT SUM(jobs_submitted) AS total_jobs_submitted
FROM project_tool_usage
WHERE project_id = 1 AND tool_id = 1;

SELECT tool_id, SUM(jobs_submitted) AS total_jobs_submitted
FROM project_tool_usage
GROUP BY tool_id;

SELECT tool_name, description
FROM tools_services
WHERE brc_domain = 'example.com';

SELECT tool_id, SUM(jobs_submitted) AS total_jobs_submitted
FROM job_status
GROUP BY tool_id;

SELECT tool_id, jobs_submitted, jobs_completed, avg_run_time
FROM job_status
WHERE tool_id = 0;
